DROP TABLE IF EXISTS `ban_pick_rooms`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ban_pick_rooms` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `created_at` datetime(6) DEFAULT NULL,
  `current_phase_index` int NOT NULL,
  `current_phase_selected_count` int NOT NULL,
  `phase_duration_seconds` int NOT NULL,
  `room_code` varchar(16) COLLATE utf8mb4_unicode_ci NOT NULL,
  `status` enum('CANCELLED','FINISHED','IN_PROGRESS','READY','WAITING') COLLATE utf8mb4_unicode_ci NOT NULL,
  `timer_started_at` datetime(6) DEFAULT NULL,
  `updated_at` datetime(6) DEFAULT NULL,
  `version` bigint DEFAULT NULL,
  `blue_user_id` bigint DEFAULT NULL,
  `guest_user_id` bigint DEFAULT NULL,
  `host_user_id` bigint NOT NULL,
  `red_user_id` bigint DEFAULT NULL,
  `phase_deadline_at` datetime(6) DEFAULT NULL,
  `guest_ready` tinyint(1) NOT NULL DEFAULT '0',
  `host_ready` tinyint(1) NOT NULL DEFAULT '0',
  `blue_series_used_hero_ids` text COLLATE utf8mb4_unicode_ci,
  `blue_used_picks_by_game` text COLLATE utf8mb4_unicode_ci,
  `current_game_number` int NOT NULL,
  `red_series_used_hero_ids` text COLLATE utf8mb4_unicode_ci,
  `red_used_picks_by_game` text COLLATE utf8mb4_unicode_ci,
  `series_type` enum('BO1','BO3','BO5','BO7') COLLATE utf8mb4_unicode_ci NOT NULL,
  `blue_lineup_confirmed` tinyint(1) NOT NULL DEFAULT '0',
  `blue_pick_order` text COLLATE utf8mb4_unicode_ci,
  `lineup_deadline_at` datetime(6) DEFAULT NULL,
  `phase_type` enum('DRAFT','LINEUP_ADJUSTMENT') COLLATE utf8mb4_unicode_ci NOT NULL,
  `red_lineup_confirmed` tinyint(1) NOT NULL DEFAULT '0',
  `red_pick_order` text COLLATE utf8mb4_unicode_ci,
  PRIMARY KEY (`id`),
  UNIQUE KEY `UKt5sxrnyxnio5ywumo026bgr47` (`room_code`),
  KEY `FK83n5o6ywvs37jm848b4ibo752` (`blue_user_id`),
  KEY `FKacspnioypnri2p1jcnx8ovxpp` (`guest_user_id`),
  KEY `FKmkghl522urf99rxuthf2u85bl` (`host_user_id`),
  KEY `FK6uum2h9h90g33mct0muljoim4` (`red_user_id`),
  CONSTRAINT `FK6uum2h9h90g33mct0muljoim4` FOREIGN KEY (`red_user_id`) REFERENCES `users` (`id`),
  CONSTRAINT `FK83n5o6ywvs37jm848b4ibo752` FOREIGN KEY (`blue_user_id`) REFERENCES `users` (`id`),
  CONSTRAINT `FKacspnioypnri2p1jcnx8ovxpp` FOREIGN KEY (`guest_user_id`) REFERENCES `users` (`id`),
  CONSTRAINT `FKmkghl522urf99rxuthf2u85bl` FOREIGN KEY (`host_user_id`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=285 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
